import React, { useEffect, useState } from 'react'
import '../css/results.css'
import '../components/css_comp/seat_selection.css'
import { useSelector } from 'react-redux'
import Result_train from '../components/result_train'
import axios from 'axios'
import { toast } from 'react-toastify'

export default function Results() {
  const home_page_info = useSelector((state) => state.var.home_page_info)
  const [loading, setLoading] = useState(false)
  const [train_name_class, setTrain_Name_Class] = useState({})
  const [all_info, setAll_info] = useState([])
  const [selected, setSelected] = useState([])  // Global selected state
  const [total_amount, setTotal_Amount] = useState(0)  // Global total amount

  useEffect(() => {
    const search_train = async () => {
      setLoading(true)
      const from_to = {
        from: home_page_info.from,
        to: home_page_info.to
      }
      try {
        const res = await axios.post('http://127.0.0.1:8000/api/train_details', from_to)
        const data = res.data.data
        const { train_class_info } = making_train_data_from_api(data)
        setTrain_Name_Class(train_class_info)
        setAll_info(data)
      } catch (error) {
        toast.warning('Data Unavailable')
        setTrain_Name_Class({})
      } finally {
        setLoading(false)
      }
    }
    search_train()
  }, [home_page_info])

  const making_train_data_from_api = (data) => {
    const dic = {}
    data.forEach(item => {
      const trainID = item.train_id
      const trainName = item.train_name
      const className = item.class_name
      if (!dic.hasOwnProperty(trainName)) {
        dic[trainName] = [trainID, className]
      } else if (!dic[trainName].includes(className)) {
        dic[trainName].push(className)
      }
    })
    return { train_class_info: dic, info: data }
  }

  const clearPreviousSelections = () => {
    setSelected([])
    setTotal_Amount(0)
  }

  return (
    <>
      <div className='results'>
        {loading ? (
          <p>Loading...</p>
        ) : (
          <section className='container-2'>
            <div className='results-Left'>
              {Object.entries(train_name_class).map(([train_name, details], index) => (
                <Result_train
                  key={train_name}
                  all_info={all_info}
                  train_name={train_name}
                  trainID_classDetails={details}
                  selected={selected}
                  setSelected={setSelected}
                  total_amount={total_amount}
                  setTotal_Amount={setTotal_Amount}
                  clearPreviousSelections={clearPreviousSelections} // Handler to clear previous selections
                />
              ))}
            </div>
          </section>
        )}
      </div>
    </>
  )
}
